    'CNOT': { opcode: 0x10, params: ['control', 'target'], desc: '受控NOT门' },
    'CZ': { opcode: 0x11, params: ['control', 'target'], desc: '受控Z门' },
    'SWAP': { opcode: 0x12, params: ['qubit1', 'qubit2'], desc: '交换门' },
